from uuid import UUID

from django.db.models import Exists, OuterRef

from ....channel.models import Channel
from ....order.models import Order
from ...core.dataloaders import DataLoader
from ...order.dataloaders import OrderByIdLoader
from .by_self import ChannelByIdLoader


class ChannelByOrderIdLoader(DataLoader[UUID, Channel]):
    context_key = "channel_by_order"

    def batch_load(self, keys):
        def with_orders(orders):
            def with_channels(channels):
                channel_map = {channel.id: channel for channel in channels}
                return [
                    channel_map.get(order.channel_id) if order else None
                    for order in orders
                ]

            channel_ids = {order.channel_id for order in orders if order}
            return (
                ChannelByIdLoader(self.context)
                .load_many(channel_ids)
                .then(with_channels)
            )

        return OrderByIdLoader(self.context).load_many(keys).then(with_orders)


class ChannelWithHasOrdersByIdLoader(DataLoader[int, Channel]):
    context_key = "channel_with_has_orders_by_id"

    def batch_load(self, keys):
        orders = Order.objects.using(self.database_connection_name).filter(
            channel=OuterRef("pk")
        )
        channels = (
            Channel.objects.using(self.database_connection_name)
            .annotate(has_orders=Exists(orders))
            .in_bulk(keys)
        )
        return [channels.get(channel_id) for channel_id in keys]

from rest_framework import permissions

from api.base.utils import get_user_auth
from addons.wiki.models import WikiPage, WikiVersion


class ContributorOrPublic(permissions.BasePermission):

    def has_object_permission(self, request, view, obj):
        assert isinstance(obj, WikiPage), f'obj must be a WikiPage, got {obj}'
        auth = get_user_auth(request)
        if request.method in permissions.SAFE_METHODS:
            return obj.node.is_public or obj.node.can_view(auth)
        return (
            obj.node.can_edit(auth)
            or obj.node.addons_wiki_node_settings.is_publicly_editable
        )

class ContributorOrPublicWikiVersion(permissions.BasePermission):

    def has_object_permission(self, request, view, obj):
        assert isinstance(obj, WikiVersion), f'obj must be a WikiVersion, got {obj}'
        auth = get_user_auth(request)
        if request.method in permissions.SAFE_METHODS:
            return obj.wiki_page.node.is_public or obj.wiki_page.node.can_view(auth)
        return obj.wiki_page.node.can_edit(auth)


class ExcludeWithdrawals(permissions.BasePermission):

    def has_object_permission(self, request, view, obj):
        assert isinstance(obj, WikiPage), f'obj must be a WikiPage, got {obj}'
        node = obj.node
        if node and node.is_retracted:
            return False
        return True


class ExcludeWithdrawalsWikiVersion(permissions.BasePermission):

    def has_object_permission(self, request, view, obj):
        assert isinstance(obj, WikiVersion), f'obj must be a WikiVersion, got {obj}'
        node = obj.wiki_page.node
        if node and node.is_retracted:
            return False
        return True

