import olympia.core.logger
from olympia import amo
from olympia.applications.models import AppVersion


class Command(BaseCommand):
    help = (
        'Add a new version of an application. Syntax: \n'
        '    ./manage.py addnewversion <application_name> <version>'
    )
    log = olympia.core.logger.getLogger('z.appversions')

    def add_arguments(self, parser):
        parser.add_argument('application_name')
        parser.add_argument('version')

    def handle(self, *args, **options):
        try:
            do_addnewversion(options['application_name'], options['version'])
        except IndexError as exc:
            raise CommandError(self.help) from exc

        msg = 'Adding version {!r} to application {!r}\n'.format(
            options['version'],
            options['application_name'],
        )
        self.log.info(msg)
        self.stdout.write(msg)


def do_addnewversion(application, version):
    if application not in amo.APPS:
        raise CommandError('Application %r does not exist.' % application)
    try:
        AppVersion.objects.create(application=amo.APPS[application].id, version=version)
    except IntegrityError as exc:
        raise CommandError(f'Version {version!r} already exists: {exc!r}') from exc

from django.core.management.base import BaseCommand, CommandError
from django.db import IntegrityError

import olympia.core.logger
from olympia.access.models import Group, GroupUser
from olympia.users.models import UserProfile


class Command(BaseCommand):
    help = 'Add a new user to a group.'

    log = olympia.core.logger.getLogger('z.users')

    def add_arguments(self, parser):
        parser.add_argument('user', type=str, help='User id or email')
        parser.add_argument('group_id', type=int, help='Group id')

    def handle(self, *args, **options):
        do_adduser(options['user'], options['group_id'])

        msg = 'Adding {user} to {group}\n'.format(
            user=options['user'], group=options['group_id']
        )
        self.log.info(msg)
        self.stdout.write(msg)


def do_adduser(user, group):
    try:
        if '@' in user:
            user = UserProfile.objects.get(email=user)
        elif user.isdigit():
            user = UserProfile.objects.get(pk=user)
        else:
            raise CommandError('Unknown input for user.')

        group = Group.objects.get(pk=group)

        GroupUser.objects.create(user=user, group=group)

    except IntegrityError as exc:
        raise CommandError('User is already in that group? %s' % exc) from exc
    except UserProfile.DoesNotExist as exc:
        raise CommandError(f'User ({user}) does not exist.') from exc
    except Group.DoesNotExist as exc:
        raise CommandError(f'Group ({group}) does not exist.') from exc

