from ...invoice import models
from ..core.context import SyncWebhookControlContext
from ..core.scalars import DateTime
from ..core.types import Job, ModelObjectType
from ..meta.types import ObjectWithMetadata
from ..order.dataloaders import OrderByIdLoader


class Invoice(ModelObjectType[models.Invoice]):
    number = graphene.String(description="Invoice number.")
    external_url = graphene.String(
        description="URL to view an invoice.",
        required=False,
        deprecation_reason="Use `url` field.",
    )
    created_at = DateTime(
        required=True, description="Date and time at which invoice was created."
    )
    updated_at = DateTime(
        required=True, description="Date and time at which invoice was updated."
    )
    message = graphene.String(description="Message associated with an invoice.")
    url = graphene.String(description="URL to view/download an invoice.")
    order = graphene.Field(
        "saleor.graphql.order.types.Order",
        description="Order related to the invoice.",
    )

    class Meta:
        description = "Represents an Invoice."
        interfaces = [ObjectWithMetadata, Job, graphene.relay.Node]
        model = models.Invoice

    @staticmethod
    def resolve_order(root: models.Invoice, info):
        def _wrap_with_sync_webhook_control_context(order):
            return SyncWebhookControlContext(node=order)

        return (
            OrderByIdLoader(info.context)
            .load(root.order_id)
            .then(_wrap_with_sync_webhook_control_context)
        )

import django_filters
import graphene
from django.db.models import Q

from ...menu.models import Menu, MenuItem
from ..core.filters import (
    FilterInputObjectType,
    ListObjectTypeFilter,
    MetadataFilterBase,
)
from ..utils.filters import filter_slug_list


def filter_menu_search(qs, _, value):
    return qs.filter(Q(name__ilike=value) | Q(slug__ilike=value))


def filter_menu_slug(qs, _, value):
    return qs.filter(slug__in=value)


def filter_menu_item_search(qs, _, value):
    return qs.filter(name__ilike=value)


class MenuFilter(MetadataFilterBase):
    search = django_filters.CharFilter(method=filter_menu_search)
    slug = ListObjectTypeFilter(input_class=graphene.String, method=filter_menu_slug)
    slugs = ListObjectTypeFilter(input_class=graphene.String, method=filter_slug_list)

    class Meta:
        model = Menu
        fields = ["search", "slug"]


class MenuItemFilter(MetadataFilterBase):
    search = django_filters.CharFilter(method=filter_menu_item_search)

    class Meta:
        model = MenuItem
        fields = ["search"]


class MenuFilterInput(FilterInputObjectType):
    class Meta:
        filterset_class = MenuFilter


class MenuItemFilterInput(FilterInputObjectType):
    class Meta:
        filterset_class = MenuItemFilter

from django.core.management.base import BaseCommand
from osf.models import OSFUser
from osf.external.messages.celery_publishers import (
    publish_deactivated_user,
    publish_reactivate_user,
    publish_merged_user,
)

actions_to_functions = {
    'deactivate': publish_deactivated_user,
    'reactivate': publish_reactivate_user,
    'merge': publish_merged_user,
}


class Command(BaseCommand):
    help = 'Sends a message to manage a user state, for test purposes only.'

    def add_arguments(self, parser):
        parser.add_argument('user_guid', type=str, help='use the guid of the user to post.')
        # Adding a new argument to specify the action to perform
        parser.add_argument(
            'action',
            type=str,
            help='The action to perform on the user (deactivate, reactivate, merge).',
            choices=['deactivate', 'reactivate', 'merge']
        )

    def handle(self, *args, **options):
        user_guid = options['user_guid']
        user = OSFUser.load(user_guid)
        action = options['action']

        # Using a mapping of action to function to simplify the control flow

        if action in actions_to_functions:
            actions_to_functions[action](user)  # Call the appropriate function
            self.stdout.write(self.style.SUCCESS(f'Successfully {action} message for user: {user._id}'))
        else:
            self.stdout.write(self.style.ERROR('Invalid action specified.'))

from django.contrib.auth.backends import BaseBackend, ModelBackend

from mayan.apps.authentication.django_authentication_backends import (
    DjangoAuthenticationBackendModelEmail,
    DjangoAuthenticationBackendWrapperMultiFactor
)


class DjangoAuthenticationBackendOTP(BaseBackend):
    def authenticate(self, request, otp_token, user):
        if user:
            if user.otp_data.is_enabled():
                if user.otp_data.verify_token(token=otp_token):
                    return user
                else:
                    return
            else:
                return user
        else:
            return


class DjangoAuthenticationBackendEmailMultiFactorOTP(
    DjangoAuthenticationBackendWrapperMultiFactor
):
    factors = (
        {
            'default': True,
            'class': DjangoAuthenticationBackendModelEmail,
            'name': 'email_password'
        },
        {
            'class': DjangoAuthenticationBackendOTP,
            'name': 'otp_token'
        }
    )


class DjangoAuthenticationBackendUsernameMultiFactorOTP(
    DjangoAuthenticationBackendWrapperMultiFactor
):
    factors = (
        {
            'default': True,
            'class': ModelBackend,
            'name': 'username_password'
        },
        {
            'class': DjangoAuthenticationBackendOTP,
